# Check the intro phrasing patterns
python3 -c "
import re
from collections import Counter

with open('/__w/go-ontology/go-ontology/src/ontology/go-edit.obo', 'r') as f:
    content = f.read()

stanzas = content.split('\n[Term]\n')
intros = Counter()
for s in stanzas:
    if 'is_obsolete: true' in s:
        m = re.search(r'comment: (.+)', s)
        if m:
            c = m.group(1).strip()
            cl = c.lower()
            if cl.startswith('this term was made obsolete because'):
                intros['This term was made obsolete because...'] += 1
            elif cl.startswith('this term was obsoleted because'):
                intros['This term was obsoleted because...'] += 1
            elif cl.startswith('the reason for obsoletion is'):
                intros['The reason for obsoletion is...'] += 1
            elif cl.startswith('the reason for obsoleting'):
                intros['The reason for obsoleting...'] += 1
            elif cl.startswith('note that this term'):
                intros['Note that this term...'] += 1
            elif cl.startswith('this term has been obsoleted'):
                intros['This term has been obsoleted...'] += 1
            elif cl.startswith('this term is'):
                intros['This term is...'] += 1
            elif cl.startswith('1.'):
                intros['1. (numbered list)'] += 1
            elif 'obsolet' in cl[:50]:
                intros['Other (contains obsolet- early)'] += 1
            else:
                intros['Other pattern'] += 1

print('=== INTRO PHRASING PATTERNS ===')
for p, count in sorted(intros.items(), key=lambda x: -x[1]):
    print(f'  {count:5d}  {p}')
" 2>&1
